patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..1c2098920a2b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4518,16 +4518,21 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
   }
   if (!match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A))))
     return nullptr;
-
-  // icmp (X ^ Y_NonZero) u>= X --> icmp (X ^ Y_NonZero) u> X
-  // icmp (X ^ Y_NonZero) u<= X --> icmp (X ^ Y_NonZero) u< X
-  // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
-  // icmp (X ^ Y_NonZero) s<= X --> icmp (X ^ Y_NonZero) s< X
-  CmpInst::Predicate PredOut = CmpInst::getStrictPredicate(Pred);
-  if (PredOut != Pred &&
-      isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
-    return new ICmpInst(PredOut, Op0, Op1);
-
+  // icmp slt ((~X) ^ Y), (~X) --> icmp sgt (X ^ Y), X
+  // icmp sle ((~X) ^ Y), (~X) --> icmp sge (X ^ Y), X
+  // icmp sgt ((~X) ^ Y), (~X) --> icmp slt (X ^ Y), X
+  // icmp sge ((~X) ^ Y), (~X) --> icmp sle (X ^ Y), X
+  // This works because (~X) ^ Y = ~(X ^ Y), and for signed comparisons,
+  // negating both operands flips the predicate direction.
+  if (ICmpInst::isSigned(Pred) && !ICmpInst::isEquality(Pred)) {
+    Value *X;
+    Value *X; const APInt *NotC; if (match(Op1, m_c_Xor(m_APInt(NotC), m_Value(X))) && NotC->isAllOnes()) {
+      CmpInst::Predicate NewPred = ICmpInst::getSwappedPredicate(Pred);
+      // Create (X ^ Y) which is the same as (Y ^ X) due to commutativity
+      Value *NewXor = IC.Builder.CreateXor(X, A);
+      return new ICmpInst(NewPred, NewXor, X);
+    }
+  }
   return nullptr;
 }

